import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [periodo, setPeriodo] = useState('');
  const [mensagem, setMensagem] = useState('');

  // Preenche campos se for edição
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome);
      setRa(alunoEditando.ra);
      setPeriodo(alunoEditando.periodo);
    } else {
      setNome('');
      setRa('');
      setPeriodo('');
    }
  }, [alunoEditando]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (alunoEditando) {
      // Editando existente
      axios.put(`/api/alunos/${alunoEditando.id}`, { nome, ra, periodo })
        .then(() => {
          setMensagem('Aluno atualizado!');
          setNome('');
          setRa('');
          setPeriodo('');
          onNovoAluno();
          onFimEdicao();
        })
        .catch((err) => setMensagem('Erro ao atualizar aluno.'));
    } else {
      // Novo aluno
      axios.post('/api/alunos', { nome, ra, periodo })
        .then(() => {
          setMensagem('Aluno cadastrado!');
          setNome('');
          setRa('');
          setPeriodo('');
          onNovoAluno();
        })
        .catch((err) => setMensagem('Erro ao cadastrar aluno.'));
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{marginBottom: 24}}>
      <h2>{alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}</h2>
      <div>
        <label>
          Nome:
          <input value={nome} onChange={e => setNome(e.target.value)} required />
        </label>
      </div>
      <div>
        <label>
          RA:
          <input value={ra} onChange={e => setRa(e.target.value)} required />
        </label>
      </div>
      <div>
        <label>
          Período:
          <input value={periodo} onChange={e => setPeriodo(e.target.value)} required />
        </label>
      </div>
      <button type="submit">{alunoEditando ? 'Atualizar' : 'Cadastrar'}</button>
      {alunoEditando && <button type="button" onClick={onFimEdicao}>Cancelar</button>}
      {mensagem && <p>{mensagem}</p>}
    </form>
  );
}

export default FormAluno;
